							"MeldingTerrormistanke-datadef-23320" : {
									"texts" : {
											"LEDE" : {
													"NOB" : "Er det mistanke om finansiering av terrorisme?"
												},
											"HJELP" : {
													"NOB" : "Hvitvaskingsloven §7 pålegger rapporteringspliktige ved mistanke om  forhold som rammes av str.l. §147a eller § 147 b å foreta nærmere  undersøkelser for å få bekreftet eller avkreftet mistanken.    §147 a\n                                    beskriver en rekke forhold som ansees som terrorhandlinger og  som  §147 b beskriver som straffbare å bidra til finansiering av.   Et  viktig poeng i denne sammenheng er å fokusere mere på midlenes bruk  enn\n                                    opprinnelse.  Det er distribuert en rekke lister over  personer/organsisasjoner som  kan settes i forbindelse med  terrorhandlinger og som  rapporteringspliktige er pålagt å følge."
												},
											"HINT" : {
													"NOB" : "Jfr. Str.l. §§147a og 147b."
												}
										},
									"$ref" : "#/definitions/MeldingTerrormistanke-datadef-23320"
								},
							"ImplisertPersonID-datadef-30126" : {
									"texts" : {
											"LEDE" : {
													"NOB" : "Implisert personID"
												},
											"HJELP" : {
													"NOB" : "Refereranse til en person fra listen med registrerte personer.  Personen som er valgt her er å regne som den impliserte i  MT-rapporten. Feltet inneholder en teknisk identifikator som må  finnes i feltet personid blant personene som er registert listen med  personer.  Det kan bare registreres en implisert person eller organisasjon pr.  MT-rapport"
												}
										},
									"$ref" : "#/definitions/ImplisertPersonID-datadef-30126"
								},
							"ImplisertOrganisasjonID-datadef-30127" : {
